export const RELAY_SCHEMA_VERSION = 1;

export const DEFAULT_COLUMNS: RelayColumn[] = [
  { id: "todo", name: "Todo", position: 1000, terminal: false },
  { id: "in_progress", name: "In Progress", position: 2000, terminal: false },
  { id: "needs_clarification", name: "Needs Clarification", position: 3000, terminal: false },
  { id: "not_doing", name: "Not Doing", position: 4000, terminal: true },
  { id: "completed", name: "Completed", position: 5000, terminal: true }
];

export type TicketPriority = "low" | "medium" | "high" | "urgent";
export type RunStatus = "idle" | "drafting" | "running" | "blocked" | "failed" | "completed" | "cancelled";
export type ProjectHealth = "ok" | "warning" | "error";
export type ThemePreference = "system" | "light" | "dark";
export type RelayActor = "user" | "codex" | "system";
export type RelayEventSource =
  | "manual_board"
  | "manual_ticket_edit"
  | "agent_execution"
  | "clarification_ui"
  | "system_reconciliation";

export type RelayColumn = {
  id: string;
  name: string;
  position: number;
  terminal: boolean;
};

export type ProjectSettings = {
  defaultModel: string | null;
  defaultApprovalPolicy: "untrusted" | "on-request" | "never";
  defaultSandboxMode: "read-only" | "workspace-write" | "danger-full-access";
  allowNonGitCodexRuns: boolean;
  ticketDraftingEnabled: boolean;
  codexExecutionEnabled: boolean;
};

export type ProjectConfig = {
  schemaVersion: number;
  projectId: string;
  name: string;
  createdAt: string;
  updatedAt: string;
  columns: RelayColumn[];
  settings: ProjectSettings;
};

export type ProjectSummary = {
  projectId: string | null;
  name: string;
  path: string;
  exists: boolean;
  isGitRepository: boolean;
  relayInitialized: boolean;
  health: ProjectHealth;
  healthMessages: string[];
  activeRunCount: number;
  swimlanes: ProjectSwimlaneSummary[];
  lastOpenedAt?: string;
};

export type ProjectSwimlaneSummary = {
  id: string;
  name: string;
  position: number;
  ticketCount: number;
};

export type GitMetadataState = "loading" | "ready" | "not_git" | "unavailable" | "missing" | "error";

export type GitMetadata = {
  state: GitMetadataState;
  isGitRepository: boolean;
  branchName: string | null;
  isDetachedHead: boolean;
  commitSha: string | null;
  isDirty: boolean;
  changedFileCount: number | null;
  message: string | null;
  error: string | null;
  updatedAt: string;
};

export type GitMetadataOptions = {
  force?: boolean;
};

export type TicketFrontMatter = {
  schemaVersion: number;
  id: string;
  title: string;
  status: string;
  position: number;
  priority: TicketPriority;
  labels: string[];
  createdAt: string;
  updatedAt: string;
  codexThreadId: string | null;
  runStatus: RunStatus;
  lastRunId: string | null;
};

export type TicketRecord = {
  frontMatter: TicketFrontMatter;
  markdown: string;
  filePath: string;
};

export type TicketSummary = TicketFrontMatter & {
  excerpt: string;
  filePath: string;
};

export type TicketReferenceCandidate = {
  id: string;
  title: string;
  status: string;
  columnName: string;
  relativePath: string;
  linkPath: string;
};

export type InvalidTicket = {
  filePath: string;
  reason: string;
};

export type BoardSnapshot = {
  project: ProjectSummary;
  config: ProjectConfig | null;
  columns: RelayColumn[];
  tickets: TicketSummary[];
  invalidTickets: InvalidTicket[];
};

export type TicketDraft = {
  title: string;
  priority: TicketPriority;
  labels: string[];
  context: string;
  researchFindings: string[];
  requirements: string[];
  implementationPlan: string[];
  acceptanceCriteria: string[];
  clarificationQuestions: string[];
  implementationNotes: string[];
  research: TicketDraftResearch;
};

export type TicketDraftResearchUrl = {
  url: string;
  status: "fetched" | "failed" | "skipped";
  title: string | null;
  reason: string | null;
  charactersRead: number;
};

export type TicketDraftResearchFile = {
  path: string;
  reason: string;
  symbols: string[];
  matches: string[];
  charactersRead: number;
};

export type TicketDraftResearchLimits = {
  maxResearchMs: number;
  maxUrls: number;
  maxUrlFetchMs: number;
  maxUrlContentChars: number;
  maxFilesToScan: number;
  maxFilesToRead: number;
  maxFileReadChars: number;
  maxMatchesPerFile: number;
};

export type TicketDraftResearch = {
  generatedAt: string;
  checkedUrls: TicketDraftResearchUrl[];
  inspectedFiles: TicketDraftResearchFile[];
  limitations: string[];
  limits: TicketDraftResearchLimits;
};

export type TicketDraftErrorCode =
  | "codex_unavailable"
  | "codex_unauthenticated"
  | "timeout"
  | "cancelled"
  | "invalid_response"
  | "backend_failure";

export type TicketDraftErrorPayload = {
  code: TicketDraftErrorCode;
  message: string;
  recoverable: boolean;
  requestId: string;
  durationMs: number;
  reason: string;
  timeoutMs?: number;
};

export type TicketDraftResult =
  | {
      ok: true;
      draft: TicketDraft;
    }
  | {
      ok: false;
      error: TicketDraftErrorPayload;
    };

export type AgentTicketUpdate = {
  title: string;
  priority: TicketPriority;
  labels: string[];
  markdown: string;
  clarificationQuestions: string[];
};

export type AgentTicketUpdateInput = {
  projectPath: string;
  ticketId: string;
  request: string;
};

export type AgentTicketUpdateStartResult = {
  runId: string;
  threadId: string;
};

export type TicketCreateInput = {
  title: string;
  priority: TicketPriority;
  labels: string[];
  markdown: string;
  status?: string;
};

export type TicketSaveInput = {
  projectPath: string;
  ticket: TicketRecord;
};

export type TicketMoveInput = {
  projectPath: string;
  ticketId: string;
  targetStatus: string;
  beforeTicketId?: string | null;
  afterTicketId?: string | null;
};

export type ClarificationAnswerType = "text";

export type ClarificationQuestion = {
  id: string;
  ticketId: string;
  question: string;
  answerType: ClarificationAnswerType;

import { shell } from "electron";
