export function ProjectSidebar({
  projects,
  selectedPath,
  gitMetadataByPath,
  loading,
  onAdd,
  onSelect,
  onRemove,
  onReveal,
  defaultExpandedProjectPaths = []
}: {
  projects: ProjectSummary[];
  selectedPath: string | null;
  gitMetadataByPath: Record<string, GitMetadata | undefined>;
  loading: boolean;
  onAdd: () => void;
