.brand p,
.topbar h1,
.topbar p {
  margin: 0;
}

.brand h1 {
  font-size: var(--relay-text-lg);
  font-weight: 620;
  line-height: 1.15;
  letter-spacing: 0;
}

.brand p {
  margin-top: 2px;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
}

.primary-button {
  border-color: transparent;
  background:
    linear-gradient(180deg, rgb(255 255 255 / 12%), transparent),
    var(--relay-primary);
  color: var(--relay-text-inverse);
  font-weight: 620;
  box-shadow:
    inset 0 1px 0 rgb(255 255 255 / 22%),
    0 12px 32px color-mix(in srgb, var(--relay-primary) 18%, transparent);
}

.primary-button:hover {
  background:
    linear-gradient(180deg, rgb(255 255 255 / 14%), transparent),
    var(--relay-primary-hover);
}

.primary-button:active {
  background: var(--relay-primary-active);
}

.primary-button:disabled {
  background: var(--relay-surface-3);
  border-color: transparent;
  color: var(--relay-text-muted);
  box-shadow: none;
}

.full {
  width: 100%;
}

.sidebar-list {
  display: flex;
  flex-direction: column;
  gap: 5px;
  min-height: 0;
  overflow-y: auto;
  padding-right: 2px;
}

.project-group {
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.project-row-shell {
  display: grid;
  grid-template-columns: 30px minmax(0, 1fr);
  align-items: stretch;
  border-radius: var(--relay-radius-md);
  border: 1px solid transparent;
  background: transparent;
  transition:
    background-color 160ms var(--relay-ease),
    border-color 160ms var(--relay-ease),
    box-shadow 180ms var(--relay-ease),
    color 160ms var(--relay-ease);
}

.project-row-shell:hover {
  background: rgb(255 255 255 / 4.5%);
  box-shadow: var(--relay-inset-highlight);
}

.project-row-shell.selected {
  border-color: transparent;
  background:
    linear-gradient(180deg, rgb(255 255 255 / 6%), transparent),
    color-mix(in srgb, var(--relay-primary-muted) 74%, transparent);
  color: var(--relay-text);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px color-mix(in srgb, var(--relay-primary) 16%, transparent),
    0 10px 24px rgb(0 0 0 / 14%);
}

.project-disclosure {
  width: 30px;
  min-height: 50px;
  border: 0;
  border-radius: var(--relay-radius-md) 0 0 var(--relay-radius-md);
  background: transparent;
  color: var(--relay-text-subtle);
  padding: 0;
  box-shadow: none;
}

.project-disclosure:hover {
  border-color: transparent;
  background: transparent;
  box-shadow: none;
}

.project-disclosure:active {
  transform: none;
}

.project-disclosure-icon {
  transition: transform 180ms var(--relay-spring);
}

.project-disclosure-icon.expanded {
  transform: rotate(90deg);
}

.project-row {
  width: 100%;
  min-width: 0;
  min-height: 50px;
  justify-content: space-between;
  text-align: left;
  padding: 9px 9px 9px 0;
  border: 0;
  border-radius: 0 var(--relay-radius-md) var(--relay-radius-md) 0;
  background: transparent;
  box-shadow: none;
}

.project-row:hover {
  border-color: transparent;
  background: transparent;
}

.project-row.selected {
  border-color: transparent;
  background: transparent;
  color: var(--relay-text);
}

.project-main {
  min-width: 0;
  display: grid;
  gap: 4px;
}

.project-name {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-weight: 560;
  color: rgb(255 255 255 / 82%);
}

.project-path {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
}

.project-badges {
  color: var(--relay-warning);
  display: flex;
  align-items: center;
  gap: var(--relay-space-1);
  flex-shrink: 0;
}

.project-main .git-metadata {
  justify-self: start;
  max-width: 100%;
  max-height: 0;
  opacity: 0;
  transform: translateY(-2px);
  transition:
    max-height 180ms var(--relay-ease),
    opacity 180ms var(--relay-ease),
    transform 180ms var(--relay-spring);
}

.project-row-shell:hover .project-main .git-metadata,
.project-row-shell:focus-within .project-main .git-metadata,
.project-row-shell.selected .project-main .git-metadata {
  max-height: 24px;
  opacity: 1;
  transform: translateY(0);
}

.project-swimlane-list {
  display: grid;
  gap: 3px;
  margin: 2px 0 var(--relay-space-2) 30px;
  padding-left: var(--relay-space-3);
  box-shadow: inset 1px 0 0 rgb(255 255 255 / 4%);
}

.project-swimlane-row {
  min-height: 30px;
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  align-items: center;
  gap: var(--relay-space-2);
  border-radius: var(--relay-radius-sm);
  color: var(--relay-text-muted);
  font-size: var(--relay-text-sm);
  padding: 5px 8px;
}

.project-swimlane-name {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.project-swimlane-count {
  min-width: 24px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5%);
  color: var(--relay-text);
  font-variant-numeric: tabular-nums;
  line-height: 1.35;
  padding: 1px 6px;
  text-align: center;
}

.project-swimlane-empty {
  min-height: 28px;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
  padding: 4px 8px;
}

.sidebar-actions {
  margin-top: auto;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--relay-space-2);
}

.workspace {
  min-width: 0;
  min-height: 0;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  padding: 16px 20px 18px;
  background:
    linear-gradient(180deg, rgb(255 255 255 / 2.4%) 0%, transparent 18%),
    linear-gradient(145deg, #111318 0%, var(--relay-bg) 44%, #0d0e11 100%);
}

.topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--relay-space-5);
  min-height: 44px;
  margin-bottom: 18px;
}

.topbar h1 {
  max-width: min(56vw, 720px);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-size: 18px;
  font-weight: 560;
  line-height: 1.2;
  letter-spacing: 0;
}

.topbar p {
  max-width: min(58vw, 760px);
  margin-top: 4px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-md);
}

.project-header-meta {
  min-width: 0;
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
  margin-top: 4px;
}

.project-header-meta p {
  margin-top: 0;
}

.topbar-actions {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-shrink: 0;
}

.search {
  width: 286px;
  min-height: 34px;
  border: 1px solid transparent;
  border-radius: var(--relay-radius-md);
  background: rgb(255 255 255 / 4.5%);
  color: var(--relay-text-subtle);
  padding: 0 10px;
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
  transition:
    background-color 160ms var(--relay-ease),
    box-shadow 180ms var(--relay-ease);
}

.search:focus-within {
  background: rgb(255 255 255 / 6%);
  box-shadow:
    var(--relay-focus-ring),
    var(--relay-inset-highlight);
}

.search input {
  min-height: 0;
  border: 0;
  border-radius: 0;
  background: transparent;
  padding: 0;
  box-shadow: none;
}

.search input:focus-visible {
  box-shadow: none;
}

.health {
  border: 0;
  border-radius: var(--relay-radius-md);
  background:
    linear-gradient(180deg, rgb(255 255 255 / 5%), transparent),
    var(--relay-warning-muted);
  color: var(--relay-warning-text);
  padding: 10px 12px;
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: var(--relay-space-3);
  box-shadow:
    var(--relay-inset-highlight),
    0 12px 28px rgb(0 0 0 / 12%);
}

.health.error {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.board {
  display: grid;
  grid-auto-columns: minmax(304px, 338px);
  grid-auto-flow: column;
  gap: 20px;
  min-height: 0;
  overflow: auto;
  padding: 4px 4px 18px;
  scroll-padding: 20px;
  transition:
    opacity 180ms var(--relay-ease),
    filter 180ms var(--relay-ease);
}

.board:focus-visible {
  outline: none;
  box-shadow: var(--relay-focus-ring);
}

.board-column {
  min-height: 0;
  border: 0;
  border-radius: var(--relay-radius-md);
  background:
    linear-gradient(180deg, rgb(255 255 255 / 4.2%) 0%, rgb(255 255 255 / 1.8%) 100%),
    color-mix(in srgb, var(--relay-surface) 76%, transparent);
  display: flex;
  flex-direction: column;
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%),
    0 18px 48px rgb(0 0 0 / 18%);
  backdrop-filter: blur(12px);
  transition:
    background-color 180ms var(--relay-ease),
    box-shadow 180ms var(--relay-ease),
    transform 180ms var(--relay-spring);
}

.board-column.over {
  transform: translateY(-2px);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px color-mix(in srgb, var(--relay-primary) 34%, transparent),
    0 24px 70px rgb(0 0 0 / 30%);
}

.column-header {

.column-header {
  min-height: 48px;
  padding: 13px 14px 8px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.column-header h2 {
  margin: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-size: var(--relay-text-base);
  font-weight: 560;
  color: rgb(255 255 255 / 74%);
}

.column-header span {
  min-width: 24px;
  height: 22px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5%);
  color: var(--relay-text-muted);
  display: grid;
  place-items: center;
  font-size: var(--relay-text-sm);
}

.column-body {
  min-height: 0;
  overflow-y: auto;
  padding: 8px 12px 14px;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.empty-column {
  min-height: 118px;
  border: 0;
  border-radius: var(--relay-radius-md);
  color: var(--relay-text-subtle);
  display: grid;
  place-items: center;
  align-content: center;
  gap: 5px;
  font-size: var(--relay-text-md);
  padding: 18px 16px;
  text-align: center;
  background:
    linear-gradient(180deg, rgb(255 255 255 / 3.5%), transparent),
    rgb(255 255 255 / 2.5%);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
  transition:
    background-color 180ms var(--relay-ease),
    box-shadow 180ms var(--relay-ease);
}

.empty-column span {
  color: var(--relay-text-muted);
  font-weight: 520;
}

.empty-column p {
  max-width: 220px;
  margin: 0;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
  line-height: 1.45;
}

.ticket-card {
  position: relative;
  border: 1px solid var(--relay-border-strong);
  border-radius: var(--relay-radius-md);
  background: var(--relay-surface-2);
  box-shadow: none;
  transition:
    opacity 180ms var(--relay-ease),
    filter 180ms var(--relay-ease),
    border-color 180ms var(--relay-ease);
}

.ticket-card:hover {
  background: var(--relay-surface-2);
  border-color: var(--relay-border-strong);
  box-shadow: none;
}

.ticket-card.keyboard-selected {
  background: var(--relay-surface-2);
  border-color: color-mix(in srgb, var(--relay-primary) 58%, var(--relay-border-strong));
  box-shadow: none;
}

.ticket-card:focus-within {
  border-color: color-mix(in srgb, var(--relay-ring) 64%, var(--relay-border-strong));
  box-shadow: none;
}

.board.board-has-focus .ticket-card:not(.keyboard-selected) {
  filter: saturate(0.72);
  opacity: 0.56;
}

.ticket-card.dragging {
  z-index: 10;
  opacity: 0.92;
  border-color: color-mix(in srgb, var(--relay-primary) 64%, var(--relay-border-strong));
  box-shadow: none;
}

.card-open {
  width: 100%;
  min-height: 0;
  display: block;
  text-align: left;
  border: 0;
  background: transparent;
  padding: 14px 42px 14px 14px;
  box-shadow: none;
  transition: none;
}

.card-open:hover {
  background: transparent;
  box-shadow: none;
  transform: none;
}

.card-open:active {
  background: transparent;
  box-shadow: none;
  transform: none;
}

.card-open:focus-visible {
  background: transparent;
  box-shadow: none;
}

.card-title {
  margin-bottom: 8px;
  color: var(--relay-text);
  font-weight: 560;
  line-height: 1.32;
}

.card-excerpt {
  display: -webkit-box;
  overflow: hidden;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 4;
  margin: 0;
  color: rgb(255 255 255 / 66%);
  font-size: var(--relay-text-md);
  line-height: 1.5;
}

.card-meta,
.labels,
.danger-row,
.detail-actions {
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.card-meta {
  margin-top: 12px;
  opacity: 0.82;
}

.priority,
.run-pill,
.labels span {
  min-height: 21px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5.5%);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  display: inline-flex;
  align-items: center;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
}

.git-metadata {
  min-width: 0;
  max-width: min(100%, 360px);
  min-height: 22px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5%);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
  white-space: nowrap;
}

.git-metadata svg {
  flex: 0 0 auto;
}

.git-metadata > span {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
}

.git-metadata.compact {
  max-width: 170px;
  padding-inline: 6px;
}

.git-metadata.git-loading {
  color: var(--relay-text-subtle);
}

.git-metadata.git-ready {
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.git-metadata.git-ready.dirty {
  background: var(--relay-warning-muted);
  color: var(--relay-warning-text);
}

.git-metadata.git-not_git,
.git-metadata.git-missing {
  background: color-mix(in srgb, var(--relay-surface-2) 70%, transparent);
  color: var(--relay-text-subtle);
}

.git-metadata.git-unavailable,
.git-metadata.git-error {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.priority.high,
.priority.urgent {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.priority.low {
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.run-pill.running,
.run-pill.blocked,
.run-pill.drafting {
  background: var(--relay-warning-muted);
  color: var(--relay-warning-text);
  box-shadow: inset 0 0 0 1px color-mix(in srgb, var(--relay-warning) 18%, transparent);
}

.run-pill.completed {
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.run-pill.failed,
.run-pill.cancelled {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.labels {
  margin-top: 10px;
  max-height: none;
  overflow: visible;
  opacity: 1;
  transform: none;
}

.labels .label-overflow {
  color: var(--relay-text-subtle);
}

.drag-handle {
  position: absolute;
  top: var(--relay-space-2);
  right: var(--relay-space-2);
  width: 28px;
  min-height: 28px;
  padding: 0;
  border-color: transparent;
  background: transparent;
  color: var(--relay-text-subtle);
  box-shadow: none;
  opacity: 1;
  transition:
    color 160ms var(--relay-ease),
    background-color 160ms var(--relay-ease);
}

.drag-handle:hover {
  color: var(--relay-text);
  background: rgb(255 255 255 / 7%);
  box-shadow: none;
  transform: none;
}

.status-rail {
  position: fixed;
  right: 14px;
  bottom: 14px;
  pointer-events: none;
}

.codex-status {
  pointer-events: all;
  width: 292px;
  border: 0;
  border-radius: var(--relay-radius-md);
  background:
    linear-gradient(180deg, rgb(255 255 255 / 7%), transparent),
    color-mix(in srgb, var(--relay-popover) 88%, transparent);
  color: var(--relay-text);
  padding: 9px;
  display: grid;
  grid-template-columns: auto 1fr auto;
  align-items: center;
  gap: 10px;
  box-shadow:
    var(--relay-inset-highlight),
    var(--relay-shadow-panel);
  backdrop-filter: blur(14px);
  animation: surface-in 240ms var(--relay-spring) both;
}

.codex-status.ok svg {
  color: var(--relay-primary-text);
}

.codex-status strong,
.codex-status span {
  display: block;
}

.codex-status strong {
  font-size: var(--relay-text-md);
}

.codex-status span {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-sm);
}

.codex-status button {
  width: 30px;
  min-height: 30px;
  padding: 0;
}

.modal-backdrop {
  position: fixed;
  inset: 0;
  z-index: 30;
  display: grid;
  place-items: center;
  background: rgb(4 5 7 / 62%);
  backdrop-filter: blur(12px);
  animation: fade-in 180ms var(--relay-ease) both;
}

.modal {
  width: min(920px, calc(100vw - 64px));
  max-height: calc(100dvh - 64px);
  overflow: auto;
  border: 0;
  border-radius: var(--relay-radius-lg);
  background:
    linear-gradient(180deg, rgb(255 255 255 / 5%) 0%, transparent 34%),
    var(--relay-popover);
  color: var(--relay-text);
  padding: 20px;
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 7%),
    var(--relay-shadow-modal);
  animation: surface-in 240ms var(--relay-spring) both;
}

.modal header,
.detail-header,
.agent-activity-panel header,
.agent-log-modal header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 14px;
}

.modal h2,
.modal p,
.detail-header h2,
.agent-activity-panel h3 {
  margin: 0;
}

.modal h2 {
  font-size: var(--relay-text-xl);
  font-weight: 580;
}

.modal p {
  margin-top: 4px;
  color: var(--relay-text-subtle);
  font-size: var(--relay-text-md);
}

.icon-button {
  width: 32px;
  min-height: 32px;
  padding: 0;
}

.modal-grid {
  display: grid;
  grid-template-columns: 1fr 184px;
  gap: var(--relay-space-3);
  margin-top: var(--relay-space-4);
  align-items: end;
}

.draft-actions {
  display: grid;
  gap: var(--relay-space-2);
}

.draft-message {
  margin-top: var(--relay-space-3);
  border: 0;
  border-radius: var(--relay-radius-md);
  background: rgb(255 255 255 / 4%);
  color: var(--relay-text-muted);
  padding: 9px 11px;
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  font-size: var(--relay-text-md);
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
}

.draft-message.error {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.field {
  display: grid;
  gap: 6px;
}

.field span {
  color: var(--relay-text-muted);
  font-size: var(--relay-text-sm);
  font-weight: 560;
}

.editor-stack {
  display: grid;
  gap: var(--relay-space-3);
  margin-top: var(--relay-space-4);
}

.draft-meta {
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.draft-meta .labels {
  margin: 0;
}

.two-fields {
  display: grid;
  grid-template-columns: 180px 1fr;

  grid-template-columns: 180px 1fr;
  gap: var(--relay-space-3);
}

.markdown-editor {
  min-height: 320px;
  font-family: var(--relay-font-mono);
