        <div className="modal-grid">
          <label className="field">
            <span>Idea</span>
            <div className="ticket-reference-editor idea-reference-editor">
              <textarea
                ref={ideaEditorRef}
                value={idea}
                placeholder="Describe what you want built..."
                aria-autocomplete="list"
                aria-controls="idea-ticket-reference-menu"
                aria-expanded={ideaTicketReferenceMenuOpen}
                onChange={(event) => {
                  setIdea(event.target.value);
                  updateTicketReferenceMention(event.target.value, event.target.selectionStart, event.target.selectionEnd);
                }}
                onFocus={(event) =>
                  updateTicketReferenceMention(event.currentTarget.value, event.currentTarget.selectionStart, event.currentTarget.selectionEnd)
                }
                onSelect={(event) =>
                  updateTicketReferenceMention(event.currentTarget.value, event.currentTarget.selectionStart, event.currentTarget.selectionEnd)
                }
                onKeyDown={handleTicketReferenceKeyDown}
                onBlur={() => {
                  window.setTimeout(closeTicketReferenceMenu, 120);
                }}
              />
              {renderTicketReferenceMenu("idea-ticket-reference-menu")}
            </div>
          </label>
          <div className="draft-actions">
            <button className="primary-button" onClick={draftTicket} disabled={busy || idea.trim().length === 0}>
              {busy ? <Loader2 className="spin" size={16} /> : draftFailure?.recoverable ? <RefreshCw size={16} /> : <Code2 size={16} />}
              {busy ? "Drafting..." : draftFailure?.recoverable ? "Retry Codex" : "Draft with Codex"}
            </button>
          </div>
        </div>

        {draftMessage && (
          <div className={clsx("draft-message", draftMessageKind)}>
            {busy && <Loader2 className="spin" size={15} />}
            <span>{draftMessage}</span>
          </div>
        )}

        {draftProgress && (
          <AgentProgressSummary
            events={[]}
            status={draftProgress.status}
            startedAt={draftProgress.startedAt}
            endedAt={draftProgress.endedAt}
            metricsAvailable={false}
          />
        )}

        {draft && (
          <div className="editor-stack">
            <div className="draft-meta" aria-label="Generated ticket metadata">
              <span className="priority">{draft.priority}</span>

    transition-duration: 1ms !important;
  }
}

@media (max-width: 900px) {
  .app-shell {
    grid-template-columns: 238px minmax(0, 1fr);
  }

  .topbar {
    flex-wrap: wrap;
  }

  .topbar h1,
  .topbar p {
    max-width: calc(100vw - 300px);
  }

  .topbar-actions {
    width: 100%;
    justify-content: flex-end;
  }

  .board {
    grid-auto-columns: minmax(260px, 300px);
  }
}

@media (max-width: 700px) {
  .app-shell {
    grid-template-columns: 1fr;
    grid-template-rows: auto minmax(0, 1fr);
  }

  .sidebar {
    max-height: 236px;
    border-right: 0;
    border-bottom: 0;
    box-shadow:
      inset 0 -1px 0 rgb(255 255 255 / 5%),
      var(--relay-inset-highlight);
  }

  .sidebar-list {
    flex-direction: row;
    overflow-x: auto;
    overflow-y: hidden;
    padding: 0 0 2px;
    align-items: flex-start;
  }

  .project-group {
    min-width: 214px;
    flex: 0 0 214px;
  }

  .project-row {
    min-width: 0;
  }

  .project-swimlane-list {
    max-height: 118px;
    overflow-y: auto;
  }

  .sidebar-actions {
    margin-top: 0;
  }

  .workspace {
    padding: var(--relay-space-3);
  }

  .topbar {
    display: grid;
    gap: var(--relay-space-3);
  }

  .topbar h1,
  .topbar p {
    max-width: calc(100vw - 24px);
  }

  .topbar-actions {
    justify-content: stretch;
  }

  .search {
    flex: 1 1 auto;
    width: auto;
  }

  .board {
    grid-auto-columns: minmax(250px, calc(100vw - 28px));
  }

  .detail-panel {
    inset: 0;
    width: auto;
    min-width: 0;
    border-left: 0;
  }

  .modal {
    width: calc(100vw - 24px);
    max-height: calc(100dvh - 24px);
  }

  .modal-grid,
  .two-fields {
    grid-template-columns: 1fr;
  }

  .status-rail {
    right: 10px;
    bottom: 10px;
    left: 10px;
  }

  .codex-status {
    width: 100%;
  }
}

@media (max-width: 520px) {
  button {
    padding-inline: 10px;
  }

  .topbar-actions,
  .modal-footer,
  .detail-actions,
  .ticket-update-actions,
  .agent-panel-actions,
  .danger-row {
    display: grid;
    grid-template-columns: 1fr;
  }

  .topbar-actions button,
  .modal-footer button,
  .detail-actions button,
  .ticket-update-actions button,
  .agent-panel-actions button,
  .danger-row button {
    width: 100%;
  }

  .agent-metrics,
  .agent-recent-row,
  .agent-log-item {
    grid-template-columns: 1fr;
  }

  .agent-log-meta {
    border-right: 0;
    border-bottom: 0;
    box-shadow: inset 0 -1px 0 rgb(255 255 255 / 5%);
  }
}

